parameters.jsCode:
const response = $input.first();
const jobDescription = $('Job Description Form').first().json['Job Description'];

if (response.json.error || !response.json.content) {
  return [{ json: { company: null, role_title: null, location: null, employment_type: null, jobDescription, extractionError: true } }];
}

const text = response.json.content[0].text.trim();
const cleaned = text.replace(/^```json\n?/, '').replace(/```$/, '').trim();

try {
  const parsed = JSON.parse(cleaned);
  return [{ json: { company: parsed.company || null, role_title: parsed.role_title || null, location: parsed.location || null, employment_type: parsed.employment_type || null, jobDescription } }];
} catch (e) {
  return [{ json: { company: null, role_title: null, location: null, employment_type: null, jobDescription, extractionError: true } }];
}

const allItems = $input.all();
const meta = $('Parse Metadata JSON').first().json;

const hasRecord = allItems.length > 0 && allItems[0].json && allItems[0].json.id;

return [{
  json: {
    isDuplicate: !!hasRecord,
    company: meta.company,
    role_title: meta.role_title,
    location: meta.location,
    employment_type: meta.employment_type,
    jobDescription: meta.jobDescription
  }
}];

const allItems = $input.all();
const meta = $('Load Profile Document').first().json;

let fitSignals = '';
let riskSignals = '';
let assessmentError = false;

for (const item of allItems) {
  if (!item.json.content || item.json.error) {
    assessmentError = true;
    break;
  }
  const text = item.json.content[0].text;
  if (!fitSignals) {
    fitSignals = text;
  } else {
    riskSignals = text;
  }
}

return [{
  json: {
    fitSignals,
    riskSignals,
    assessmentError,
    company: meta.company,
    role_title: meta.role_title,
    location: meta.location,
    employment_type: meta.employment_type
  }
}];

const response = $input.first();
const combinedData = $('Combine for Synthesis').first().json;

if (!response.json.content || response.json.error) {
  return [{ json: { ...combinedData, synthesisText: null, recommendation: null, synthesisError: true } }];
}

const text = response.json.content[0].text;
const enumMatch = text.match(/\*\*Recommendation:\*\*\s*(Strong Fit|Moderate Fit|Weak Fit|Do Not Apply)/);
const recommendation = enumMatch ? enumMatch[1] : null;

return [{
  json: {
    ...combinedData,
    synthesisText: text,
    recommendation,
    synthesisError: !recommendation
  }
}];
